_____javascript
return await space.current.renderWidget({
  id: "starter-widget",
  name: "Analog Clock",
  cols: 4,
  rows: 4,
  renderer: async (parent) => {
    parent.innerHTML = `
      <div style="display:flex;align-items:center;justify-content:center;height:100%;background:#111;color:#fff;font-family:sans-serif;">
        <div style="text-align:center">
          <div style="font-size:18px;font-weight:600;margin-bottom:8px;">Analog Clock</div>
          <div id="clock-time" style="font-size:28px;letter-spacing:1px;"></div>
        </div>
      </div>
    `
    const el = parent.querySelector("#clock-time")
    const tick = () => {
      const now = new Date()
      el.textContent = now.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit", second: "2-digit" })
    }
    tick()
    setInterval(tick, 1000)
  }
})

